-- supabase/migrations/018_seed_service_category_pages.sql
-- Registers the 4 service category pages in the pages table and seeds their sections.

DO $$
DECLARE
  fmr_id uuid;
  sm_id  uuid;
  al_id  uuid;
  fh_id  uuid;
BEGIN

  -- ── 1. Upsert pages ──────────────────────────────────────────────────────────
  INSERT INTO pages (site_id, title_i18n, slug, type, status, sort_order)
  VALUES
    ('00000000-0000-0000-0000-000000000001', $j${"es":"Full Mouth Reconstruction","en":"Full Mouth Reconstruction"}$j$::jsonb, '/servicios/full-mouth-reconstruction', 'landing', 'published', 10),
    ('00000000-0000-0000-0000-000000000001', $j${"es":"Smile Makeover","en":"Smile Makeover"}$j$::jsonb,                 '/servicios/smile-makeover',              'landing', 'published', 11),
    ('00000000-0000-0000-0000-000000000001', $j${"es":"Aligners","en":"Aligners"}$j$::jsonb,                             '/servicios/aligners',                    'landing', 'published', 12),
    ('00000000-0000-0000-0000-000000000001', $j${"es":"Facial Harmony","en":"Facial Harmony"}$j$::jsonb,                 '/servicios/facial-harmony',              'landing', 'published', 13)
  ON CONFLICT (site_id, slug) DO UPDATE SET title_i18n = EXCLUDED.title_i18n;

  -- ── 2. Fetch page ids ─────────────────────────────────────────────────────────
  SELECT id INTO fmr_id FROM pages WHERE site_id = '00000000-0000-0000-0000-000000000001' AND slug = '/servicios/full-mouth-reconstruction';
  SELECT id INTO sm_id  FROM pages WHERE site_id = '00000000-0000-0000-0000-000000000001' AND slug = '/servicios/smile-makeover';
  SELECT id INTO al_id  FROM pages WHERE site_id = '00000000-0000-0000-0000-000000000001' AND slug = '/servicios/aligners';
  SELECT id INTO fh_id  FROM pages WHERE site_id = '00000000-0000-0000-0000-000000000001' AND slug = '/servicios/facial-harmony';

  -- ── 3. Clear existing sections ────────────────────────────────────────────────
  DELETE FROM sections WHERE page_id IN (fmr_id, sm_id, al_id, fh_id);

  -- ══════════════════════════════════════════════════════════════════════════════
  -- FULL MOUTH RECONSTRUCTION
  -- ══════════════════════════════════════════════════════════════════════════════
  INSERT INTO sections (page_id, type, sort_order, is_visible, settings) VALUES

  (fmr_id, 'page_header', 0, true, $j${"style":"dark-centered","eyebrow":{"es":"Odontología Integral","en":"Comprehensive Dentistry"},"title":{"es":"Allura Full Mouth Reconstruction™","en":"Allura Full Mouth Reconstruction™"},"subtitle":{"es":"Solución integral para recuperar función, estabilidad y una sonrisa que vuelva a sentirse segura.","en":"Comprehensive solution to restore function, stability and a smile that feels secure again."},"imageUrl":"/images/imagenes_web/Allura-Full-Mouth-Reconstruction.jpg","ctaLabel":{"es":"","en":""},"ctaUrl":"","breadcrumb":{"es":"","en":""}}$j$::jsonb),

  (fmr_id, 'text_image', 1, true, $j${"title":{"es":"Un plan hecho a tu medida","en":"A plan tailored for you"},"body":{"es":"Para pacientes que han perdido piezas, presentan deterioro severo o necesitan una rehabilitación completa, diseñamos un plan integral respaldado por tecnología 3D de última generación y un equipo de especialistas altamente certificados. Cada caso es único y cada plan es hecho a medida.","en":"For patients who have lost teeth, have severe deterioration, or need complete rehabilitation, we design a comprehensive plan backed by cutting-edge 3D technology and a team of highly certified specialists. Each case is unique and every plan is made to measure."},"imageUrl":"/images/imagenes_web/Allura-Full-Mouth-Reconstruction.jpg","imagePosition":"right"}$j$::jsonb),

  (fmr_id, 'cards_grid', 2, true, $j${"internalName":"Tratamientos FMR","eyebrow":{"es":"Nuestros tratamientos","en":"Our treatments"},"title":{"es":"Especialidades incluidas","en":"Included specialties"},"subtitle":{"es":"","en":""},"columns":3,"bg":"light","cardStyle":"bordered","cards":[{"icon":"🦷","title":{"es":"Implantes Unitarios y Múltiples","en":"Single and Multiple Implants"},"body":{"es":"Reemplazo de una o varias piezas dentales con implantes de titanio de alta precisión, integrados para durar toda la vida.","en":"Replacement of one or several teeth with high-precision titanium implants, integrated to last a lifetime."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🏆","title":{"es":"Implantes All-on-X","en":"All-on-X Implants"},"body":{"es":"Solución completa para pacientes con pérdida total o casi total de piezas: una arcada completa fija sobre 4 o 6 implantes estratégicamente ubicados.","en":"Complete solution for patients with total or near-total tooth loss: a complete fixed arch on 4 or 6 strategically placed implants."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🔬","title":{"es":"Rehabilitación Oral Completa","en":"Full Oral Rehabilitation"},"body":{"es":"Tratamiento integral que restaura función masticatoria, estética y salud periodontal para casos de deterioro severo o múltiple.","en":"Comprehensive treatment that restores masticatory function, aesthetics and periodontal health for severe or multiple deterioration."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"✨","title":{"es":"Prótesis Fijas sobre Implantes","en":"Fixed Prostheses on Implants"},"body":{"es":"Coronas y puentes de porcelana fijados permanentemente sobre implantes. Aspecto natural, resistencia total y funcionalidad completa.","en":"Porcelain crowns and bridges permanently fixed on implants. Natural appearance, total resistance and complete functionality."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🔄","title":{"es":"Reemplazo de Restauraciones Fallidas","en":"Replacement of Failed Restorations"},"body":{"es":"Evaluación y sustitución de restauraciones antiguas, fracturadas o con infiltración. Volvemos a empezar sobre una base sana.","en":"Evaluation and replacement of old, fractured or infiltrated restorations. Starting over on a healthy foundation."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🖥️","title":{"es":"Planificación Digital 3D","en":"3D Digital Planning"},"body":{"es":"Simulación completa de tu caso con tecnología CAD/CAM y escáner intraoral 3D antes de comenzar cualquier procedimiento.","en":"Complete simulation of your case with CAD/CAM technology and 3D intraoral scanner before starting any procedure."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""}]}$j$::jsonb),

  (fmr_id, 'cta', 3, true, $j${"eyebrow":{"es":"Da el primer paso","en":"Take the first step"},"title":{"es":"Transforma tu bienestar.","en":"Transform your wellbeing."},"subtitle":{"es":"","en":""},"buttonLabel":{"es":"Contactar ahora","en":"Contact us now"}}$j$::jsonb);

  -- ══════════════════════════════════════════════════════════════════════════════
  -- SMILE MAKEOVER
  -- ══════════════════════════════════════════════════════════════════════════════
  INSERT INTO sections (page_id, type, sort_order, is_visible, settings) VALUES

  (sm_id, 'page_header', 0, true, $j${"style":"dark-centered","eyebrow":{"es":"Estética Dental","en":"Dental Aesthetics"},"title":{"es":"Allura Smile Makeover™","en":"Allura Smile Makeover™"},"subtitle":{"es":"Tu sonrisa, rediseñada con precisión artística. Cada detalle, pensado para ti.","en":"Your smile, redesigned with artistic precision. Every detail, crafted for you."},"imageUrl":"/images/imagenes_web/Cosmetic_dentistry_allurahealthcare.jpg","ctaLabel":{"es":"","en":""},"ctaUrl":"","breadcrumb":{"es":"","en":""}}$j$::jsonb),

  (sm_id, 'text_image', 1, true, $j${"title":{"es":"Arte y ciencia en cada sonrisa","en":"Art and science in every smile"},"body":{"es":"Combinamos diseño digital, carillas en porcelana y tecnología de vanguardia para que cada sonrisa sea única, natural y proyecte exactamente lo que quieres transmitir. Nuestros especialistas en estética dental trabajan con criterio artístico y rigor clínico en cada caso.","en":"We combine digital design, porcelain veneers and cutting-edge technology so that each smile is unique, natural and projects exactly what you want to convey. Our dental aesthetics specialists work with artistic judgment and clinical rigor in every case."},"imageUrl":"/images/imagenes_web/Cosmetic_dentistry_allurahealthcare.jpg","imagePosition":"right"}$j$::jsonb),

  (sm_id, 'cards_grid', 2, true, $j${"internalName":"Tratamientos Smile Makeover","eyebrow":{"es":"Nuestros tratamientos","en":"Our treatments"},"title":{"es":"Especialidades incluidas","en":"Included specialties"},"subtitle":{"es":"","en":""},"columns":3,"bg":"light","cardStyle":"bordered","cards":[{"icon":"✨","title":{"es":"Carillas en Porcelana","en":"Porcelain Veneers"},"body":{"es":"Láminas ultrafinas de porcelana adheridas a los dientes para transformar color, forma y alineación con resultados ultranaturales.","en":"Ultra-thin porcelain wafers bonded to teeth to transform color, shape and alignment with ultra-natural results."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🖥️","title":{"es":"Diseño Digital de Sonrisa","en":"Digital Smile Design"},"body":{"es":"Simulación digital de tu nueva sonrisa antes de comenzar. Ves el resultado final y apruebas cada detalle antes del primer procedimiento.","en":"Digital simulation of your new smile before you begin. See the final result and approve every detail before the first procedure."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"👑","title":{"es":"Coronas en Porcelana","en":"Porcelain Crowns"},"body":{"es":"Fundas de porcelana de alta resistencia que restauran dientes dañados devolviéndoles apariencia, función y resistencia totales.","en":"High-strength porcelain caps that restore damaged teeth, returning their appearance, function and resistance."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🔬","title":{"es":"Restauraciones Estéticas Avanzadas","en":"Advanced Aesthetic Restorations"},"body":{"es":"Técnicas adhesivas de última generación para corregir fracturas, manchas, diastemas y deformidades con mínima invasión.","en":"State-of-the-art adhesive techniques to correct fractures, stains, diastemas and deformities with minimal invasion."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"⚪","title":{"es":"Blanqueamiento Dental Profesional","en":"Professional Teeth Whitening"},"body":{"es":"Protocolo clínico de blanqueamiento supervisado por especialistas para resultados seguros, uniformes y duraderos.","en":"Clinical whitening protocol supervised by specialists for safe, uniform and lasting results."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""}]}$j$::jsonb),

  (sm_id, 'cta', 3, true, $j${"eyebrow":{"es":"Da el primer paso","en":"Take the first step"},"title":{"es":"Transforma tu bienestar.","en":"Transform your wellbeing."},"subtitle":{"es":"","en":""},"buttonLabel":{"es":"Contactar ahora","en":"Contact us now"}}$j$::jsonb);

  -- ══════════════════════════════════════════════════════════════════════════════
