  INSERT INTO sections (page_id, type, sort_order, is_visible, settings) VALUES

  (al_id, 'page_header', 0, true, $j${"style":"dark-centered","eyebrow":{"es":"Ortodoncia Invisible","en":"Invisible Orthodontics"},"title":{"es":"Allura Aligners™","en":"Allura Aligners™"},"subtitle":{"es":"Ortodoncia sin brackets, con planificación digital y seguimiento remoto para pacientes internacionales.","en":"Bracket-free orthodontics with digital planning and remote monitoring for international patients."},"imageUrl":"/images/imagenes_web/Invisalign_Allurahealthcare_.jpg","ctaLabel":{"es":"","en":""},"ctaUrl":"","breadcrumb":{"es":"","en":""}}$j$::jsonb),

  (al_id, 'text_image', 1, true, $j${"title":{"es":"Ortodoncia diseñada para tu vida","en":"Orthodontics designed for your life"},"body":{"es":"Usamos Invisalign y alineadores de última generación para lograr alineaciones precisas con total discreción. Planificación personalizada y seguimiento remoto para pacientes internacionales que no pueden volver a Medellín en cada etapa.","en":"We use Invisalign and next-generation aligners to achieve precise alignments with complete discretion. Personalized digital planning and remote follow-up for international patients who cannot return to Medellín at every stage."},"imageUrl":"/images/imagenes_web/Invisalign_Allurahealthcare_.jpg","imagePosition":"right"}$j$::jsonb),

  (al_id, 'cards_grid', 2, true, $j${"internalName":"Tratamientos Aligners","eyebrow":{"es":"Nuestros tratamientos","en":"Our treatments"},"title":{"es":"Especialidades incluidas","en":"Included specialties"},"subtitle":{"es":"","en":""},"columns":3,"bg":"light","cardStyle":"bordered","cards":[{"icon":"😁","title":{"es":"Invisalign","en":"Invisalign"},"body":{"es":"Proveedor oficial Invisalign con especialistas certificados Diamond Top Doctor. Planificación digital precisa para tu caso.","en":"Official Invisalign provider with Diamond Top Doctor-certified specialists. Precise digital planning for your case."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"✨","title":{"es":"Alineadores Transparentes","en":"Clear Aligners"},"body":{"es":"Ortodoncia con alineadores como alternativa o complemento a Invisalign, personalizada para cada paciente.","en":"Clear aligner orthodontics as an alternative or complement to Invisalign, personalized for each patient."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🖥️","title":{"es":"Escaneo Digital 3D","en":"3D Digital Scanning"},"body":{"es":"Escáner intraoral 3D para tomar impresiones digitales completas: adiós a los moldes tradicionales.","en":"3D intraoral scanning for complete digital impressions: no more traditional molds."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"📋","title":{"es":"Planificación Personalizada","en":"Personalized Planning"},"body":{"es":"Simulación digital completa del movimiento de tu sonrisa, caso a caso, antes de comenzar el tratamiento.","en":"Complete digital simulation of your smile movement, case by case, before starting treatment."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🌍","title":{"es":"Seguimiento Remoto","en":"Remote Monitoring"},"body":{"es":"Control post-tratamiento internacional mediante fotos, escaneos y videollamadas con tu especialista.","en":"International post-treatment follow-up via photos, scans and video