  (al_id, 'cta', 3, true, $j${"eyebrow":{"es":"Da el primer paso","en":"Take the first step"},"title":{"es":"Transforma tu bienestar.","en":"Transform your wellbeing."},"subtitle":{"es":"","en":""},"buttonLabel":{"es":"Contactar ahora","en":"Contact us now"}}$j$::jsonb);

  -- ══════════════════════════════════════════════════════════════════════════════
  -- FACIAL HARMONY
  -- ══════════════════════════════════════════════════════════════════════════════
  INSERT INTO sections (page_id, type, sort_order, is_visible, settings) VALUES

  (fh_id, 'page_header', 0, true, $j${"style":"dark-centered","eyebrow":{"es":"Medicina Facial Estética","en":"Facial Aesthetic Medicine"},"title":{"es":"Allura Facial Harmony™","en":"Allura Facial Harmony™"},"subtitle":{"es":"Medicina facial estética de precisión para realzar tus rasgos con naturalidad.","en":"Precision facial aesthetic medicine to enhance your features naturally."},"imageUrl":"/images/imagenes_web/cirugia-estetica-facial-allurahealthcare.png","ctaLabel":{"es":"","en":""},"ctaUrl":"","breadcrumb":{"es":"","en":""}}$j$::jsonb),

  (fh_id, 'text_image', 1, true, $j${"title":{"es":"Belleza que se siente auténtica","en":"Beauty that feels authentic"},"body":{"es":"Nuestro equipo de especialistas trabaja con técnicas mínimamente invasivas y protocolos internacionales para resultados que se ven auténticos y duraderos. Cada plan facial se diseña tras una evaluación estructural de tus proporciones, tipo de piel y objetivos personales.","en":"Our team of specialists works with minimally invasive techniques and international protocols for results that look authentic and lasting. Each facial plan is designed after structural evaluation of your proportions, skin type and personal goals."},"imageUrl":"/images/imagenes_web/cirugia-estetica-facial-allurahealthcare.png","imagePosition":"right"}$j$::jsonb),

  (fh_id, 'cards_grid', 2, true, $j${"internalName":"Tratamientos Facial Harmony","eyebrow":{"es":"Nuestros tratamientos","en":"Our treatments"},"title":{"es":"Especialidades incluidas","en":"Included specialties"},"subtitle":{"es":"","en":""},"columns":3,"bg":"light","cardStyle":"bordered","cards":[{"icon":"👁️","title":{"es":"Evaluación Facial Estructural","en":"Structural Facial Assessment"},"body":{"es":"Análisis detallado de proporciones, volúmenes y dinámica facial para diseñar un plan personalizado y natural.","en":"Detailed analysis of proportions, volumes and facial dynamics to design a personalized and natural plan."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"💉","title":{"es":"Toxina Botulínica y Rellenos","en":"Botulinum Toxin and Fillers"},"body":{"es":"Protocolos de aplicación precisa para suavizar líneas de expresión y restaurar volúmenes faciales con aspecto natural.","en":"Precise application protocols for softening expression lines and restoring facial volumes with a natural look."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"✨","title":{"es":"Bioestimuladores y Rejuvenecimiento","en":"Biostimulators and Rejuvenation"},"body":{"es":"Tratamientos para regenerar colágeno y mejorar la calidad de la piel desde adentro: firmeza, luminosidad y textura.","en":"Treatments to regenerate collagen and improve skin quality from within: firmness, luminosity and texture."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"👀","title":{"es":"Blefaroplastia","en":"Blepharoplasty"},"body":{"es":"Corrección quirúrgica de párpados para una mirada más descansada y juvenil, con resultados naturales y recuperación rápida.","en":"Surgical correction of eyelids for a more rested and youthful look, with natural results and fast recovery."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"👃","title":{"es":"Rinoplastia","en":"Rhinoplasty"},"body":{"es":"Remodelación nasal con técnica abierta o cerrada, adaptada a cada estructura facial para resultados armoniosos y naturales.","en":"Nasal remodeling with open or closed technique, adapted to each facial structure for harmonious and natural results."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🏥","title":{"es":"Lifting Facial","en":"Facelift"},"body":{"es":"Rejuvenecimiento facial quirúrgico que reposiciona tejidos y reduce signos visibles de envejecimiento sin aspecto artificial.","en":"Surgical facial rejuvenation that repositions tissues and reduces visible signs of aging without an artificial look."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🎯","title":{"es":"Mentoplastia","en":"Mentoplasty"},"body":{"es":"Aumento o reducción del mentón para mejorar las proporciones faciales y fortalecer el perfil mentón-cuello.","en":"Chin augmentation or reduction to improve facial proportions and strengthen the chin-neck profile."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""},{"icon":"🔬","title":{"es":"Coordinación con Cirugía Maxilofacial","en":"Maxillofacial Surgery Coordination"},"body":{"es":"Coordinación con cirujanos maxilofaciales para casos complejos que combinan correcciones estéticas y funcionales.","en":"Coordination with maxillofacial surgeons for complex cases combining aesthetic and functional corrections."},"imageUrl":"","ctaLabel":{"es":"","en":""},"ctaUrl":""}]}$j$::jsonb),

  (fh_id, 'cta', 3, true, $j${"eyebrow":{"es":"Da el primer paso","en":"Take the first step"},"title":{"es":"Transforma tu bienestar.","en":"Transform your wellbeing."},"subtitle":{"es":"","en":""},"buttonLabel":{"es":"Contactar ahora","en":"Contact us now"}}$j$::jsonb);

